mapper.select:
SELECT event_pk, user_no, product_no, b, n, k, is_applied, created_dt
FROM event
WHERE user_no = #{userNo}
AND product_no = #{productNo}

mapper.update:
UPDATE event
SET
    b = #{b},
    n = #{n},
    k = #{k}
WHERE user_no = #{userNo}
AND product_no = #{productNo}

UPDATE event
SET is_applied = 'Y'
WHERE user_no = #{userNo}
AND product_no = #{productNo}
